"use client";

import Link from 'next/link';
import { motion } from 'framer-motion';
import {
  Mail,
  Phone,
  MapPin,
  Facebook,
  Twitter,
  Linkedin,
  Instagram,
  ArrowUpRight,
  Send
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import Image from 'next/image';

const footerLinks = {
  services: [
    { label: 'Web Application', href: '/services/web-application' },
    { label: 'Mobile Application', href: '/services/mobile-application' },
    { label: 'Digital Marketing', href: '/services/digital-marketing' },
    { label: 'Data Science/AI', href: '/services/data-science-ai' },
  ],
  company: [
    { label: 'About Us', href: '/about' },
    { label: 'Career', href: '/career' },
    { label: 'Contact', href: '/contact' },
    { label: 'Our Trainers', href: '/trainer/our-trainers' },
  ],
  programs: [
    { label: 'Ambassador Program', href: '/join/ambassador-program' },
    { label: 'Become a Trainer', href: '/trainer/apply' },
    { label: 'Data Ambassadors', href: '/join/data-ambassadors' },
  ],
};

const socialLinks = [
  { icon: Facebook, href: '#', label: 'Facebook' },
  { icon: Twitter, href: '#', label: 'Twitter' },
  { icon: Linkedin, href: '#', label: 'LinkedIn' },
  { icon: Instagram, href: '#', label: 'Instagram' },
];

export const Footer = () => {
  return (
    <footer className="relative bg-[#001529] text-white overflow-hidden border-t border-white/5">
      {/* --- Dynamic Moving Gradient Background --- */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <motion.div 
          animate={{
            scale: [1, 1.2, 1],
            x: [0, 50, 0],
            y: [0, 30, 0],
          }}
          transition={{
            duration: 20,
            repeat: Infinity,
            ease: "linear"
          }}
          className="absolute -top-[20%] -left-[10%] w-[70%] h-[70%] bg-accent/10 blur-[120px] rounded-full" 
        />
        <motion.div 
          animate={{
            scale: [1, 1.3, 1],
            x: [0, -40, 0],
            y: [0, -50, 0],
          }}
          transition={{
            duration: 15,
            repeat: Infinity,
            ease: "linear"
          }}
          className="absolute -bottom-[20%] -right-[10%] w-[60%] h-[60%] bg-blue-500/10 blur-[100px] rounded-full" 
        />
      </div>

      <div className="container mx-auto px-5 sm:px-8 relative z-10">
        {/* CTA Section */}
        <div className="py-16 md:py-24 border-b border-white/10">
          <div className="max-w-4xl mx-auto text-center">
            <motion.h2
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              className="text-3xl sm:text-4xl lg:text-5xl font-display font-bold mb-6 tracking-tight"
            >
              Ready to <span className="text-accent">Transform</span> Your Business?
            </motion.h2>
            <motion.p
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: 0.1 }}
              className="text-base sm:text-lg text-white/60 mb-10 max-w-2xl mx-auto leading-relaxed"
            >
              Let&apos;s discuss how we can help you achieve your goals with data-driven solutions and cutting-edge technology.
            </motion.p>
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: 0.2 }}
              className="flex flex-col sm:flex-row gap-5 justify-center items-center"
            >
              <Button asChild size="lg" className="w-full sm:w-auto bg-accent text-accent-foreground hover:bg-accent/90 px-10 py-7 text-base font-bold shadow-2xl shadow-accent/20 transition-all hover:-translate-y-1">
                <Link href="/contact" className="flex items-center gap-2">
                  Get Started Today
                  <ArrowUpRight className="w-5 h-5" />
                </Link>
              </Button>
              {/* REFINED Learn More Button */}
              <Button asChild size="lg" variant="outline" className="w-full sm:w-auto border-white/20 bg-white/5 backdrop-blur-sm text-white hover:bg-white/10 px-10 py-7 text-base transition-all hover:-translate-y-1">
                <Link href="/about">Learn More</Link>
              </Button>
            </motion.div>
          </div>
        </div>

        {/* Main Content Grid */}
        <div className="py-16 md:py-24 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-y-12 gap-x-8 md:gap-x-12">
          
          {/* Brand Info */}
          <div className="sm:col-span-2 lg:col-span-2 space-y-8">
            <Link href="/" className="flex items-center gap-4 group w-fit">
            <Image
                src="/logo.png"
                alt="Data Experts 360 Logo"
                width={40}
                height={40}
              />
              <span className="font-display font-bold text-2xl tracking-tighter">
                Data Experts <span className="text-accent">360</span>
              </span>
            </Link>
            <p className="text-white/60 text-base leading-relaxed max-w-md">
              Empowering businesses with data-driven solutions, innovative technology,
              and expert consulting services for sustainable growth.
            </p>

            <div className="pt-4">
              <h4 className="font-bold text-xs uppercase tracking-[0.2em] text-accent/80 mb-5">Newsletter</h4>
              <div className="flex max-w-sm gap-2 p-1.5 bg-white/5 border border-white/10 rounded-2xl focus-within:ring-2 focus-within:ring-accent/50 transition-all duration-300">
                <Input
                  type="email"
                  placeholder="Your email address"
                  className="bg-transparent border-none text-white placeholder:text-white/30 focus-visible:ring-0 h-12"
                />
                <Button size="icon" className="bg-accent hover:bg-accent/90 shrink-0 h-12 w-12 rounded-xl shadow-lg">
                  <Send className="w-5 h-5" />
                </Button>
              </div>
            </div>
          </div>

          {/* Nav Links */}
          <div className="space-y-8">
            <h4 className="font-display font-bold text-xl relative inline-block">
              Services
              <span className="absolute -bottom-2 left-0 w-8 h-1 bg-accent rounded-full" />
            </h4>
            <ul className="space-y-4">
              {footerLinks.services.map((link) => (
                <li key={link.href}>
                  <Link
                    href={link.href}
                    className="text-white/50 hover:text-accent transition-all flex items-center gap-2 group text-base"
                  >
                    <span className="w-0 group-hover:w-4 h-[1px] bg-accent transition-all duration-300" />
                    {link.label}
                  </Link>
                </li>
              ))}
            </ul>
          </div>

          <div className="space-y-8">
            <h4 className="font-display font-bold text-xl relative inline-block">
              Company
              <span className="absolute -bottom-2 left-0 w-8 h-1 bg-accent rounded-full" />
            </h4>
            <ul className="space-y-4">
              {footerLinks.company.map((link) => (
                <li key={link.href}>
                  <Link
                    href={link.href}
                    className="text-white/50 hover:text-accent transition-all flex items-center gap-2 group text-base"
                  >
                    <span className="w-0 group-hover:w-4 h-[1px] bg-accent transition-all duration-300" />
                    {link.label}
                  </Link>
                </li>
              ))}
            </ul>
          </div>

          {/* Contact Details */}
          <div className="space-y-8">
            <h4 className="font-display font-bold text-xl relative inline-block">
              Contact
              <span className="absolute -bottom-2 left-0 w-8 h-1 bg-accent rounded-full" />
            </h4>
            <ul className="space-y-6">
              {[
                { icon: Mail, label: 'Email', val: 'info@dataexperts360.com' },
                { icon: Phone, label: 'Phone', val: '+1 (555) 123-4567' },
                { icon: MapPin, label: 'Office', val: 'Tech City, TC 12345' }
              ].map((item, idx) => (
                <li key={idx} className="flex items-start gap-4 group">
                  <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center shrink-0 border border-white/10 group-hover:border-accent/50 transition-colors">
                    <item.icon className="w-5 h-5 text-accent" />
                  </div>
                  <div>
                    <p className="text-[10px] uppercase text-white/40 font-black tracking-widest">{item.label}</p>
                    <p className="text-white/70 text-sm md:text-base">{item.val}</p>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="py-10 border-t border-white/10 flex flex-col-reverse md:flex-row justify-between items-center gap-8">
          <div className="text-center md:text-left space-y-3">
            <p className="text-sm text-white/40">
              © {new Date().getFullYear()} Data Experts 360. All rights reserved.
            </p>
            <div className="flex gap-6 justify-center md:justify-start text-xs text-white/30 uppercase tracking-[0.2em] font-bold">
              <Link href="#" className="hover:text-accent transition-colors">Privacy Policy</Link>
              <Link href="#" className="hover:text-accent transition-colors">Terms of Service</Link>
            </div>
          </div>
          
          <div className="flex items-center gap-4">
            {socialLinks.map((social) => (
              <a
                key={social.label}
                href={social.href}
                aria-label={social.label}
                className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center border border-white/10 hover:border-accent hover:bg-accent hover:text-[#001529] transition-all duration-500 group"
              >
                <social.icon className="w-5 h-5 transition-transform group-hover:scale-110" />
              </a>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
};